import boto3

logs  = boto3.client("logs")
s3    = boto3.client("s3")


# 1. Set CloudWatch Logs group retention (hot tier only — 30 days for app logs)
def set_log_group_retention(group_name: str, days: int) -> None:
    logs.put_retention_policy(
        logGroupName=group_name,
        retentionInDays=days,   # Allowed values: 1, 3, 5, 7, 14, 30, 60, 90, …
    )

set_log_group_retention("/app/claude-api", 30)
set_log_group_retention("/app/audit",       30)   # Audit also leaves CW after 30d — S3 takes over


# 2. S3 lifecycle for app-log exports (warm then delete)
s3.put_bucket_lifecycle_configuration(
    Bucket="prod-app-logs",
    LifecycleConfiguration={
        "Rules": [
            {
                "ID": "app-logs-tiering",
                "Status": "Enabled",
                "Filter": {"Prefix": "app-logs/"},
                "Transitions": [
                    # Move to cheaper Intelligent-Tiering at 31 days
                    {"Days": 31, "StorageClass": "INTELLIGENT_TIERING"},
                ],
                "Expiration": {"Days": 90},   # delete after 90 days total
            }
        ]
    },
)


# 3. S3 lifecycle for audit logs (warm → Glacier → very long-lived)
s3.put_bucket_lifecycle_configuration(
    Bucket="prod-audit-logs-immutable",
    LifecycleConfiguration={
        "Rules": [
            {
                "ID": "audit-logs-archive",
                "Status": "Enabled",
                "Filter": {"Prefix": ""},
                "Transitions": [
                    {"Days": 91,   "StorageClass": "GLACIER"},
                    {"Days": 2557, "StorageClass": "DEEP_ARCHIVE"},   # 7 years
                ],
                "Expiration": {"Days": 3650},   # 10 years hard delete
            }
        ]
    },
)

from opentelemetry import trace
from opentelemetry.sdk.trace import TracerProvider
from opentelemetry.sdk.trace.sampling import (
    ALWAYS_OFF, ALWAYS_ON,
    ParentBased, TraceIdRatioBased,
)
from opentelemetry.sdk.trace.export import BatchSpanProcessor
from opentelemetry.exporter.otlp.proto.grpc.trace_exporter import OTLPSpanExporter


class ClaudeAdaptiveSampler:
    # Sample 1% normally; 100% on errors/retries; 10% on latency outliers.

    def should_sample(self, parent_context, trace_id, name, kind, attributes, links):
        from opentelemetry.sdk.trace.sampling import Decision, SamplingResult

        # Always sample error spans (set by upstream logic via baggage/attribute)
        if attributes and attributes.get("error") is True:
            return SamplingResult(Decision.RECORD_AND_SAMPLE)

        if attributes and attributes.get("claude.retry_count", 0) > 0:
            return SamplingResult(Decision.RECORD_AND_SAMPLE)

        # Ratio-based otherwise — 1% base rate
        ratio_sampler = TraceIdRatioBased(0.01)
        return ratio_sampler.should_sample(
            parent_context, trace_id, name, kind, attributes, links
        )

    def get_description(self) -> str:
        return "ClaudeAdaptiveSampler(base=1%, errors=100%, retries=100%)"


provider = TracerProvider(sampler=ClaudeAdaptiveSampler())
exporter = OTLPSpanExporter(endpoint="http://otel-collector:4317", insecure=True)
provider.add_span_processor(BatchSpanProcessor(exporter))
trace.set_tracer_provider(provider)

