#!/usr/bin/env python3
# scripts/check-retention-compliance.py
# Fails non-zero if any S3 bucket in the log namespace has no lifecycle rule,
# or if a rule's expiration exceeds the policy maximum.

import sys
import boto3
from dataclasses import dataclass

POLICY = {
    "prod-app-logs":             {"max_days": 90},
    "prod-audit-logs-immutable": {"max_days": 3650},
    "prod-infra-logs":           {"max_days": 60},
}

@dataclass
class Finding:
    bucket: str
    issue: str

def check_bucket(s3, bucket: str, max_days: int) -> list[Finding]:
    findings = []
    try:
        resp = s3.get_bucket_lifecycle_configuration(Bucket=bucket)
        rules = resp.get("Rules", [])
        if not rules:
            findings.append(Finding(bucket, "No lifecycle rules configured"))
            return findings
        for rule in rules:
            expiry = rule.get("Expiration", {}).get("Days")
            if expiry and expiry > max_days:
                findings.append(Finding(
                    bucket,
                    f"Expiration {expiry}d exceeds policy maximum {max_days}d "
                    f"(rule: {rule.get('ID')})"
                ))
    except s3.exceptions.NoSuchLifecycleConfiguration:
        findings.append(Finding(bucket, "No lifecycle configuration"))
    return findings

def main() -> int:
    s3 = boto3.client("s3")
    all_findings = []
    for bucket, policy in POLICY.items():
        all_findings.extend(check_bucket(s3, bucket, policy["max_days"]))

    if all_findings:
        for f in all_findings:
            print(f"FAIL [{f.bucket}]: {f.issue}", file=sys.stderr)
        return 1

    print(f"OK: {len(POLICY)} buckets checked, all compliant")
    return 0

if __name__ == "__main__":
    sys.exit(main())
